const msg = $json.message;
if (!msg) throw new Error('No message in trigger payload');
return [{
  json: {
    chat_id: String(msg.chat.id),
    user_message: msg.text || '',
    user_name: msg.from?.first_name || 'Usuario'
  }
}];

// Detectar intención del mensaje para saber qué consultar en Supabase
const msg = $json.user_message.toLowerCase();
let intent = 'general';

if (msg.includes('cliente') || msg.includes('clientes')) intent = 'clientes';
else if (msg.includes('póliza') || msg.includes('poliza') || msg.includes('vencer') || msg.includes('vencen')) intent = 'polizas';
else if (msg.includes('siniestro') || msg.includes('urgente')) intent = 'siniestros';
else if (msg.includes('cotiza') || msg.includes('cotización')) intent = 'cotizaciones';

return [{
  json: {
    ...$json,
    intent
  }
}];

const intent = $node['Code — Detectar intención'].json.intent;
const userMsg = $node['Code — Detectar intención'].json.user_message;
const data = $json;

let contexto = '';
try {
  const items = Array.isArray(data) ? data : [data];
  if (intent === 'clientes') {
    contexto = `Clientes en base de datos: ${items.length > 0 ? JSON.stringify(items[0]) : 'sin datos'}`;
  } else if (intent === 'polizas') {
    contexto = `Pólizas próximas a vencer (7 días): ${items.length} encontradas. Detalle: ${JSON.stringify(items.slice(0,5))}`;
  } else if (intent === 'siniestros') {
    contexto = `Siniestros abiertos: ${items.length}. Detalle: ${JSON.stringify(items.slice(0,5))}`;
  } else if (intent === 'cotizaciones') {
    contexto = `Cotizaciones pendientes: ${items.length}. Detalle: ${JSON.stringify(items.slice(0,5))}`;
  } else {
    contexto = `Datos generales: ${JSON.stringify(items[0])}`;
  }
} catch(e) {
  contexto = 'No se pudo obtener datos de Supabase en este momento.';
}

return [{
  json: {
    chat_id: $node['Code — Extraer datos'].json.chat_id,
    user_message: userMsg,
    contexto_supabase: contexto
  }
}];

const chatId = $node['Code — Preparar contexto'].json.chat_id;
const text = $json.choices?.[0]?.message?.content || 'Sin respuesta';
if (!chatId) throw new Error('chat_id perdido');
return [{ json: { chat_id: chatId, response_text: text } }];
